            if count.get(&digit).copied().unwrap_or(0) == digit {
                return false;
            }
            *count.entry(digit).or_insert(0) += 1;
        }
        true
    }

    let mut candidate = n + 1;
    while true {
        if is_palindrome(candidate) && is_valid(candidate) {
            return candidate;
        }
        candidate += 1;
    }
}
